class Solution(object):
    def maximumSafenessFactor(self, grid):
        from collections import deque
        n = len(grid)
        multi_source_bfs = deque()
        dist = [[float('inf')] * n for _ in range(n)]
        for i in range(n):
            for j in range(n):
                if grid[i][j] == 1:
                    dist[i][j] = 0
                    multi_source_bfs.append((i, j))
        while multi_source_bfs:
            r, c = multi_source_bfs.popleft()
            for dr, dc in [(0,1), (1,0), (0,-1), (-1,0)]:
                nr, nc = r + dr, c + dc
                if 0 <= nr < n and 0 <= nc < n and dist[nr][nc] > dist[r][c] + 1:
                    dist[nr][nc] = dist[r][c] + 1
                    multi_source_bfs.append((nr, nc))
        def can_reach(min_safe):
            if dist[0][0] < min_safe:
                return False
            visited = set([(0, 0)])
            q = deque([(0, 0)])
            while q:
                r, c = q.popleft()
                if r == n - 1 and c == n - 1:
                    return True
                for dr, dc in [(0,1), (1,0), (0,-1), (-1,0)]:
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < n and 0 <= nc < n and (nr, nc) not in visited and dist[nr][nc] >= min_safe:
                        visited.add((nr, nc))
                        q.append((nr, nc))
            return False
        left, right = 0, 2 * n
        result = 0
        while left <= right:
            mid = (left + right) // 2
            if can_reach(mid):
                result = mid
                left = mid + 1
            else:
                right = mid - 1
        return result
